@inject IJSRuntime JS
@implements IAsyncDisposable

<div @ref="_dropZoneRef" class="file-drop-zone @(_isDragOver ? "drag-over" : "")">
    <p>Drag &amp; drop files here</p>
</div>

@if (_files.Count > 0)
{
    <ul class="file-drop-zone-list">
        @foreach (var entry in _files)
        {
            <li>
                @if (entry.Error is not null)
                {
                    <span class="file-error">
                        <strong>@entry.Info.Name</strong> &mdash; @entry.Error
                    </span>
                }
                else
                {
                    <span>
                        <strong>@entry.Info.Name</strong>
                        &mdash; @FormatSize(entry.Info.Size)
                        &mdash; @entry.Info.Type
                    </span>
                }
                <button class="btn-remove" @onclick="() => Remove(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10 * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;
    private bool _isDragOver;
    private readonly List<FileEntry> _files = new();

    private sealed record FileEntry(FileInfo Info, string? Error);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/FileDropZone.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            await _module.InvokeVoidAsync("initDropZone", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public void OnDragOver(bool over)
    {
        _isDragOver = over;
        InvokeAsync(StateHasChanged);
    }

    [JSInvokable]
    public async Task OnDropFiles(FileInfo[] droppedFiles)
    {
        _isDragOver = false;

        foreach (var file in droppedFiles)
        {
            string? error = file.Size > MaxFileSize
                ? $"File exceeds 10 MB limit ({FormatSize(file.Size)})"
                : null;
            _files.Add(new FileEntry(file, error));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task Remove(FileEntry entry)
    {
        _files.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _files
            .Where(f => f.Error is null)
            .Select(f => f.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try { await _module.InvokeVoidAsync("dispose", _dropZoneRef); } catch { }
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

const zones = new Map();

export function initDropZone(element, dotNetRef) {
    function onDragOver(e) {
        e.preventDefault();
        dotNetRef.invokeMethodAsync('OnDragOver', true);
    }

    function onDragLeave(e) {
        e.preventDefault();
        dotNetRef.invokeMethodAsync('OnDragOver', false);
    }

    function onDrop(e) {
        e.preventDefault();
        const files = Array.from(e.dataTransfer.files).map(f => ({
            name: f.name,
            size: f.size,
            type: f.type || 'unknown'
        }));
        dotNetRef.invokeMethodAsync('OnDropFiles', files);
    }

    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    zones.set(element, { onDragOver, onDragLeave, onDrop });
}

export function dispose(element) {
    const handlers = zones.get(element);
    if (handlers) {
        element.removeEventListener('dragover', handlers.onDragOver);
        element.removeEventListener('dragleave', handlers.onDragLeave);
        element.removeEventListener('drop', handlers.onDrop);
        zones.delete(element);
    }
}

.file-drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
    color: #6c757d;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.file-drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-drop-zone-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-drop-zone-list li {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-error {
    color: #dc3545;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.2rem 0.5rem;
    cursor: pointer;
    margin-left: 1rem;
    flex-shrink: 0;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

