const zones = new Map();

export function initDropZone(element, dotNetRef) {
    function onDragOver(e) {
        e.preventDefault();
        dotNetRef.invokeMethodAsync('OnDragOver', true);
    }

    function onDragLeave(e) {
        e.preventDefault();
        dotNetRef.invokeMethodAsync('OnDragOver', false);
    }

    function onDrop(e) {
        e.preventDefault();
        const files = Array.from(e.dataTransfer.files).map(f => ({
            name: f.name,
            size: f.size,
            type: f.type || 'unknown'
        }));
        dotNetRef.invokeMethodAsync('OnDropFiles', files);
    }

    element.addEventListener('dragover', onDragOver);
    element.addEventListener('dragleave', onDragLeave);
    element.addEventListener('drop', onDrop);

    zones.set(element, { onDragOver, onDragLeave, onDrop });
}

export function dispose(element) {
    const handlers = zones.get(element);
    if (handlers) {
        element.removeEventListener('dragover', handlers.onDragOver);
        element.removeEventListener('dragleave', handlers.onDragLeave);
        element.removeEventListener('drop', handlers.onDrop);
        zones.delete(element);
    }
}

